+  const handleExportModalToPDF = async (elementRef: React.RefObject<HTMLDivElement>, fileName: string) => {
+    if (!elementRef.current) {
+      console.error('Element reference not found');
+      return;
+    }
+    
+    setIsExportingTestPDF(true);
+    try {
+      const element = elementRef.current;
+      const originalStyle = element.getAttribute('style') || '';
+      
+      element.style.maxHeight = 'none';
+      element.style.height = 'auto';
+      element.style.overflow = 'visible';
+      
+      const bodyEl = element.querySelector('.overflow-y-auto') as HTMLElement;
+      let originalBodyStyle = '';
+      if (bodyEl) {
+        originalBodyStyle = bodyEl.getAttribute('style') || '';
+        bodyEl.style.maxHeight = 'none';
+        bodyEl.style.height = 'auto';
+        bodyEl.style.overflow = 'visible';
+      }
+
+      const buttonsToHide = element.querySelectorAll('button') as NodeListOf<HTMLButtonElement>;
+      const originalButtonsDisplay: string[] = [];
+      buttonsToHide.forEach((btn, idx) => {
+        originalButtonsDisplay[idx] = btn.style.display;
+        if (btn.innerText.includes('Baixar') || btn.innerText.includes('Fechar') || btn.querySelector('svg')) {
+          btn.style.display = 'none';
+        }
+      });
+
+      const canvas = await html2canvas(element, {
+        scale: 2,
+        useCORS: true,
+        logging: false,
+        backgroundColor: '#ffffff',
+        onclone: (clonedDoc) => {
+          const elements = clonedDoc.querySelectorAll('*');
+          elements.forEach((el) => {
+            const htmlEl = el as HTMLElement;
+            const styleAttr = htmlEl.getAttribute('style') || '';
+            if (styleAttr.includes('oklch') || styleAttr.includes('oklab')) {
+              const newStyle = styleAttr.replace(/(oklch|oklab)\([^)]+\)/g, '#7c3aed');
+              htmlEl.setAttribute('style', newStyle);
+            }
+          });
+        }
+      });
+
+      element.setAttribute('style', originalStyle);
+      if (bodyEl) {
+        bodyEl.setAttribute('style', originalBodyStyle);
+      }
+      buttonsToHide.forEach((btn, idx) => {
+        btn.style.display = originalButtonsDisplay[idx];
+      });
+
+      const imgData = canvas.toDataURL('image/jpeg', 0.8);
+      const pdf = new jsPDF('p', 'mm', 'a4');
+      const pdfWidth = pdf.internal.pageSize.getWidth();
+      const pdfHeight = (canvas.height * pdfWidth) / canvas.width;
+      const pageHeight = pdf.internal.pageSize.getHeight();
+
+      let heightLeft = pdfHeight;
+      let position = 0;
+
+      pdf.addImage(imgData, 'JPEG', 0, position, pdfWidth, pdfHeight, undefined, 'FAST');
+      heightLeft -= pageHeight;
+
+      while (heightLeft >= 0) {
+        position = heightLeft - pdfHeight;
+        pdf.addPage();
+        pdf.addImage(imgData, 'JPEG', 0, position, pdfWidth, pdfHeight, undefined, 'FAST');
+        heightLeft -= pageHeight;
+      }
+
+      pdf.save(`${fileName.replace(/\s+/g, '_').toUpperCase()}.pdf`);
+    } catch (error) {
+      console.error('Error generating PDF:', error);
+      alert('Houve um erro ao gerar o PDF do teste. Por favor, tente novamente.');
+    } finally {
+      setIsExportingTestPDF(false);
+    }
+  };
+
